package oop;

public class Employees {
 
String name;
int salary;
public Employees(String name, int salary) {
	super();
	this.name = name;
	this.salary = salary;
}
public Employees() {
	// TODO Auto-generated constructor stub
}
@Override
public String toString() {
	return "Employee [name=" + name + ", salary=" + salary + "]";
}
 
 
	
	
}
 
